use rusqlite::{Connection, Result};

fn authenticate(conn: &Connection, username: &str, password: &str) -> bool {
    let mut stmt = conn.prepare_cached("SELECT count(*) FROM users WHERE username=?1 AND password=?")? ;
    let row = stmt.query_row([username, password], |row| row.get(0)).unwrap();

    match row.get(0) {
        Ok(count) => count > 0,
        Err(e) => false, // An error occurred
    }
}